/* BTTooltipPaginationStep — PaginationStep / pagination-step balloon.
   Figma: node 2157-1726 (Playground instance with full PaginationStep).
   Figma pagination step variants: node 478-2463.
   All colours via @btech/tokens CSS vars — no hex fallbacks (CLAUDE.md §6). */

/* ── Outer wrapper (arrow + body stacked or side-by-side) ── */

.bt-tooltip-step {
  display: inline-flex;
  flex-direction: column; /* default: top arrow */
  width: 320px;
  max-width: calc(100vw - 32px);
}

.bt-tooltip-step--top    { flex-direction: column-reverse; } /* body on top, arrow below  */
.bt-tooltip-step--bottom { flex-direction: column; }          /* arrow on top, body below  */
.bt-tooltip-step--left   { flex-direction: row-reverse; align-items: flex-start; width: auto; }
.bt-tooltip-step--right  { flex-direction: row;         align-items: flex-start; width: auto; }

/* ── Arrow row / col ──────────────────────────────────────────────────────────
   Arrow position is driven by the CSS custom property --bt-arrow-offset:
     • horizontal (top/bottom): px from the balloon's left edge to arrow centre
     • vertical   (left/right): px from the balloon's top  edge to arrow centre

   Default values come from the arrowPosition modifier class (enum-to-px map).
   The parent showcase can override by setting an arrowOffset prop, which the
   component applies as an inline style (inline > class specificity).         */

/* Enum-based fallback values ─────────────────────────────────────────────── */
.bt-tooltip-step__arrow-row--left      { --bt-arrow-offset: 24px; }
.bt-tooltip-step__arrow-row--left-mid  { --bt-arrow-offset: 25%; }
.bt-tooltip-step__arrow-row--mid       { --bt-arrow-offset: 50%; }
.bt-tooltip-step__arrow-row--right-mid { --bt-arrow-offset: 75%; }
.bt-tooltip-step__arrow-row--right     { --bt-arrow-offset: calc(100% - 24px); }

.bt-tooltip-step__arrow-col--left      { --bt-arrow-offset: 24px; }
.bt-tooltip-step__arrow-col--left-mid  { --bt-arrow-offset: 25%; }
.bt-tooltip-step__arrow-col--mid       { --bt-arrow-offset: 50%; }
.bt-tooltip-step__arrow-col--right-mid { --bt-arrow-offset: 75%; }
.bt-tooltip-step__arrow-col--right     { --bt-arrow-offset: calc(100% - 24px); }

/* Horizontal arrow wrapper (top / bottom) */
.bt-tooltip-step__arrow-row {
  position: relative;
  width: 320px;
  max-width: calc(100vw - 32px);
  height: 8px;
  flex-shrink: 0;
}

.bt-tooltip-step__arrow-row .bt-tooltip-step__arrow {
  position: absolute;
  left: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* Vertical arrow wrapper (left / right) */
.bt-tooltip-step__arrow-col {
  position: relative;
  width: 8px;
  flex-shrink: 0;
  align-self: stretch;
}

.bt-tooltip-step__arrow-col .bt-tooltip-step__arrow {
  position: absolute;
  top: calc(var(--bt-arrow-offset, 50%) - 8px);
}

/* ── Body card ── */

.bt-tooltip-step__body {
  background: var(--bg-inverse);
  border-radius: var(--radius-sm);
  padding: var(--space-lg);
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
  width: 320px;
  max-width: calc(100vw - 32px);
  box-sizing: border-box;
}

.bt-tooltip-step--left  .bt-tooltip-step__body,
.bt-tooltip-step--right .bt-tooltip-step__body {
  width: max-content;
  min-width: 250px;
  max-width: 320px;
}

/* ── Header row (label + close button) ── */

.bt-tooltip-step__header {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  width: 100%;
}

.bt-tooltip-step__label {
  flex: 1;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-md);
  font-weight: 700;
  line-height: var(--typography-line-height-sm);
  color: var(--text-inverse);
  margin: 0;
}


/* ── Description ── */

.bt-tooltip-step__description {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-inverse);
  margin: 0;
}

/* ── Footer row (step label + navigation buttons) ── */

.bt-tooltip-step__footer {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  width: 100%;
}

/* Centered variant — everything centred, no step text on left */
.bt-tooltip-step__footer--centered {
  justify-content: center;
  gap: var(--space-md);
}

.bt-tooltip-step__step-label {
  flex: 1;
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-inverse);
  margin: 0;
}

/* Step label in centered variant — no flex */
.bt-tooltip-step__footer--centered .bt-tooltip-step__step-label {
  flex: none;
}

/**
 * BTTooltipPaginationStep — type definitions shared between Vue and React.
 * PaginationStep / pagination-step tooltip balloon.
 * Figma: https://www.figma.com/design/WANr9drWYNYbMPuT2sMeHi/?node-id=478-2463
 */

/** Navigation button style inside the step footer. */
export type BTTooltipPaginationStepVariant = 'button' | 'link' | 'centered';

/** Which side the arrow caret appears on. */
export type BTTooltipPaginationStepPosition = 'top' | 'bottom' | 'left' | 'right';

/** Arrow offset along its axis (same semantics as BTTooltipArrowPosition). */
export type BTTooltipPaginationStepArrowPosition =
  | 'left'
  | 'left-mid'
  | 'mid'
  | 'right-mid'
  | 'right';

export interface BTTooltipPaginationStepProps {
  /** Bold title shown at the top of the card. Hidden when omitted. */
  label?: string;
  /** Main description text. Required. */
  description: string;
  /** Step indicator text, e.g. "Step 1 of 5". Hidden when omitted. */
  stepLabel?: string;
  /**
   * Navigation button style.
   * - `button` (default) — secondary rounded buttons (Prev / Next).
   * - `link` — text-link buttons (grey Prev / blue Next).
   * - `centered` — icon-only chevron buttons flanking the step label.
   */
  stepVariant?: BTTooltipPaginationStepVariant;
  /**
   * Show a × close button in the top-right corner.
   * Clicking it fires `@close` / `onClose`. @default false
   */
  hasClose?: boolean;
  /** Prev button label. @default 'Prev' */
  prevLabel?: string;
  /** Next button label. @default 'Next' */
  nextLabel?: string;
  /** Which side the arrow caret renders on. @default 'top' */
  position?: BTTooltipPaginationStepPosition;
  /** Arrow offset along the axis. @default 'mid' */
  arrowPosition?: BTTooltipPaginationStepArrowPosition;
}

export { default as BTTooltipPaginationStep } from './BTTooltipPaginationStep.vue';
export type {
  BTTooltipPaginationStepProps,
  BTTooltipPaginationStepVariant,
  BTTooltipPaginationStepPosition,
  BTTooltipPaginationStepArrowPosition,
} from './BTTooltipPaginationStep.types';
